import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.servlet.view.RedirectView;

@RestController
public class OAuthController {

    private static final String AUTH_URL = "YOUR_AUTHORIZATION_SERVER_URL";
    private static final String CLIENT_ID = "YOUR_CLIENT_ID";
    private static final String REDIRECT_URI = "YOUR_REDIRECT_URI";
    private static final String SCOPE = "YOUR_SCOPE";
    private static final String RESPONSE_TYPE = "YOUR_RESPONSE_TYPE";

    @GetMapping("/oauth/authorize")
    public RedirectView authorize(@RequestParam String redirectUri) {
        String authorizationUrl = AUTH_URL + "?client_id=" + CLIENT_ID +
                "&redirect_uri=" + redirectUri +
                "&scope=" + SCOPE +
                "&response_type=" + RESPONSE_TYPE;
        return new RedirectView(authorizationUrl);
    }
}